import type { ObjectTypeDefinition, PrimaryKeyType } from "@osdk/api";
import type { CollectionStorageData } from "../base-list/BaseCollectionQuery.js";
import type { CacheKey } from "../CacheKey.js";
import type { Canonical } from "../Canonical.js";
import type { SimpleWhereClause } from "../SimpleWhereClause.js";
import type { SpecificLinkQuery } from "./SpecificLinkQuery.js";
export declare const SOURCE_OBJECT_TYPE_IDX = 0;
export declare const SOURCE_PK_IDX = 1;
export declare const LINK_NAME_IDX = 2;
export declare const WHERE_CLAUSE_IDX = 3;
export declare const ORDER_BY_CLAUSE_IDX = 4;
/**
* Storage data format for link query cache entries, similar to ListStorageData
*/
export interface LinkStorageData extends CollectionStorageData {}
/**
* Cache key for a specific link query that uniquely identifies:
* - The source object type
* - The source object primary key
* - The link name
*/
export interface SpecificLinkCacheKey extends CacheKey<"specificLink", LinkStorageData, SpecificLinkQuery, [sourceObjectType: string, sourcePk: PrimaryKeyType<ObjectTypeDefinition>, linkName: string, whereClause: Canonical<SimpleWhereClause>, orderByClause: Canonical<Record<string, "asc" | "desc" | undefined>>]> {}
